content:
1412			if err != nil {
1413				return fmt.Errorf("could not get MachineConfig %q for MachineConfigPool %q: %w", mcp.Spec.Configuration.Name, mcp.Name, err)
1414			}
1415	
1416			targetMosb, err := buildrequest.NewMachineOSBuild(buildrequest.MachineOSBuildOpts{
1417				MachineConfig:     mc,
1418				MachineOSConfig:   mosc,
1419				MachineConfigPool: mcp,
1420			})
1421			if err != nil {
1422				return fmt.Errorf("could not generate name for target MOSB: %w", err)
1423			}
1424	
1425			// Now, check if a MOSB with that name already exists.
1426			existingMosb, err := b.machineOSBuildLister.Get(targetMosb.Name)
1427			if err == nil {
1428				// A MOSB for our target config was found. Check its status
1429				mosbState := ctrlcommon.NewMachineOSBuildState(existingMosb)
1430	
1431				if mosbState.IsInTransientState() {
1432					klog.Infof("pool %q: MOSB (%s) is in a transient state. Please allow time for MOSB to finish updating.", mcp.Name, existingMosb.Name)
1433					return nil
1434				}
1435	
1436				// if MOSB state is successful, this can mean one of two things:
1437				// 1. Applied MC triggered a MOSB build through `needsImageRebuild`, and it completed, but we are waiting for spec == status in the node update
1438				// 2. Current MOSB state is successful, and a deleted MC triggered a MOSB build through `needsImageRebuild`.
1439				if mosbState.IsBuildSuccess() {
1440					// Next, we should check if the image associated with the MachineOSBuild still exists.
1441					info, err := b.inspectImage(ctx, string(existingMosb.Status.DigestedImagePushSpec), existingMosb)
1442					// If the image exists, reuse it.
1443					if info != nil && err == nil {
1444						klog.Infof("pool %q: Found successful build for target whose image exists. Reusing image.", mcp.Name)
1445						return b.reuseImageForNewMOSB(ctx, mosc, existingMosb)
1446					}
1447	
1448					// If the image does not exist, rebuild it.
1449					if imagepruner.IsImageNotFoundErr(err) {
1450						klog.Infof("pool %q: Found successful build for target whose image no longer exists. Will rebuild.", mcp.Name)
1451						return b.createNewMachineOSBuildOrReuseExisting(ctx, mosc, true)
1452					}
1453	
1454					// If we could not inspect the image, we might not have permissions to
1455					// do so, or it could be another issue. Either way, we should return an
1456					// error here.
1457					return fmt.Errorf("could not inspect image %s for MachineOSBuild %s for MachineConfigPool %s: %w", string(existingMosb.Status.DigestedImagePushSpec), existingMosb.Name, mcp.Name, err)
1458				}
1459			} else if !k8serrors.IsNotFound(err) {
1460				// An actual error occurred (not just "not found"). Return the error.
1461				return fmt.Errorf("could not get target MOSB %s: %w", targetMosb.Name, err)
1462			}
1463	
1464		} else if oldRendered != newRendered && !needsImageRebuild {
1465			klog.Infof("pool %q: No new image needs to be created, reusing last MOSB (layer-only change)", mcp.Name)
1466			prevPullSpec := mosc.Status.CurrentImagePullSpec
1467			oldMOSB, err := utils.GetMachineOSBuildForImagePullspec(string(prevPullSpec), b.utilListers())
1468			if err != nil {
1469				return fmt.Errorf("failed to look up MachineOSBuild for pull-spec %q: %w", prevPullSpec, err)
1470			}
1471			return b.reuseImageForNewMOSB(ctx, mosc, oldMOSB)
1472		}
1473		return b.createNewMachineOSBuildOrReuseExisting(ctx, mosc, needsImageRebuild)
1474	
1475	}
