1477	// reuseImageForNewMOSB creates a new MOSB (for the new rendered-MC name)
1478	// but populates its status from oldMosb so that no build actually runs.
1479	func (b *buildReconciler) reuseImageForNewMOSB(ctx context.Context, mosc *mcfgv1.MachineOSConfig, oldMosb *mcfgv1.MachineOSBuild,
1480	) error {
1481		// Look up the MCP associated with the MOSC
1482		mcp, err := b.machineConfigPoolLister.Get(mosc.Spec.MachineConfigPool.Name)
1483		if err != nil {
1484			return err
1485		}
1486	
1487		mc, err := b.machineConfigLister.Get(mcp.Spec.Configuration.Name)
1488		if err != nil {
1489			return err
1490		}
1491	
1492		// Build the new MOSB object. this is our "promise", we will eventually check if we will proceed with this
1493		newMosb, err := buildrequest.NewMachineOSBuild(
1494			buildrequest.MachineOSBuildOpts{
1495				MachineConfig:     mc,
1496				MachineOSConfig:   mosc,
1497				MachineConfigPool: mcp,
1498			})
1499	
1500		if err != nil {
1501			return err
1502		}
1503		// todo (dkhater): push the SetOwnerReferences() part into the NewMachineOSBuild() constructor
1504		// since we already have the MOSC there and it feels like something the MOSB constructor should be setting.
1505	
1506		// set the ownder of the new MOSB to be the MOSC so we can garbage collect this later
1507		newMosb.SetOwnerReferences([]metav1.OwnerReference{
1508			*metav1.NewControllerRef(mosc, mcfgv1.SchemeGroupVersion.WithKind("MachineOSConfig")),
1509		})
1510	
1511		// check if a MOSB with the newly generated name already exists in the cluster
1512		_, err = b.machineOSBuildLister.Get(newMosb.Name)
1513		if k8serrors.IsNotFound(err) {
1514			// create the new MOSB object
1515			if newMosb, err = b.mcfgclient.
1516				MachineconfigurationV1().
1517				MachineOSBuilds().
1518				Create(ctx, newMosb, metav1.CreateOptions{}); err != nil {
1519				return err
1520			}
1521		} else if err != nil {
1522			return err
1523		}
1524	
1525		image := string(oldMosb.Status.DigestedImagePushSpec)
1526	
1527		inspect, err := b.inspectImage(ctx, image, newMosb)
1528		// this is our "reality check": try to inspect the image in the registry to see if it still exists
1529		switch {
1530		// image is found, we will reuse this image
1531		case inspect != nil && err == nil:
1532			klog.Infof("Existing MachineOSBuild %q found, reusing image %q by assigning to MachineOSConfig %q", newMosb.Name, image, mosc.Name)
1533		// we are unauthorized and need to report this
1534		case err != nil && (k8serrors.IsUnauthorized(err) || imagepruner.IsAccessDeniedErr(err)):
1535			return fmt.Errorf("authentication failed while inspecting image %q for MachineOSBuild %q: %w", image, newMosb.Name, err)
1536		// image does not exist, so we delete MOSB and rebuild
1537		case err != nil && (k8serrors.IsNotFound(err) || imagepruner.IsImageNotFoundErr(err)):
1538			klog.Infof("Deleting MachineOSBuild %q and rebuilding", newMosb.Name)
1539			if deleteErr := b.mcfgclient.MachineconfigurationV1().MachineOSBuilds().Delete(ctx, newMosb.Name, metav1.DeleteOptions{}); deleteErr != nil && !k8serrors.IsNotFound(deleteErr) {
1540				return fmt.Errorf("could not delete MachineOSBuild %q: %w", newMosb.Name, deleteErr)
1541			}
1542			return nil
1543		default:
1544			return fmt.Errorf("unexpected error inspecting image %q for MachineOSBuild %q: %w", image, newMosb.Name, err)
1545		}
1546	
1547		// get the latest version of the new MOSB object to ensure we update it correctly
1548		toUpdate, err := b.getMachineOSBuildForUpdate(newMosb)
1549		if err != nil {
1550			return err
1551		}
1552		// store the current status
1553		oldStatus := toUpdate.Status
1554	
1555		// copy image url
1556		toUpdate.Status.DigestedImagePushSpec = oldMosb.Status.DigestedImagePushSpec
1557	
1558		// set conditions on new MOSB status to succeeded
1559		for _, c := range apihelpers.MachineOSBuildSucceededConditions() {
1560			apihelpers.SetMachineOSBuildCondition(&toUpdate.Status, c)
1561		}
1562	
1563		// update MOSB object with the status
1564		if err := b.setStatusOnMachineOSBuildIfNeeded(ctx, toUpdate, oldStatus, toUpdate.Status); err != nil {
1565			return err
1566		}
1567	
1568		// update parent MOSC status to point to newly built (aka the reused) MOSB
1569		return b.updateMachineOSConfigStatus(ctx, mosc, toUpdate)
1570	}
