1572	// getObjectsForImagePruner retrieves the secret for the MachineOSBuild and the ControllerConfig for use by the imagepruner.
1573	func (b *buildReconciler) getObjectsForImagePruner(mosb *mcfgv1.MachineOSBuild) (*corev1.Secret, *mcfgv1.ControllerConfig, error) {
1574		secretName := mosb.Annotations[constants.RenderedImagePushSecretAnnotationKey]
1575	
1576		if secretName == "" {
1577			return nil, nil, fmt.Errorf("MachineOSBuild %s missing annotation %s", mosb.Name, constants.RenderedImagePushSecretAnnotationKey)
1578		}
1579	
1580		secret, err := b.kubeclient.CoreV1().Secrets(ctrlcommon.MCONamespace).Get(context.TODO(), secretName, metav1.GetOptions{})
1581		if err != nil {
1582			return nil, nil, fmt.Errorf("could not get rendered push secret %s: %w", secretName, err)
1583		}
1584	
1585		controllerConfigs, err := b.listers.controllerConfigLister.List(labels.Everything())
1586		if err != nil {
1587			return nil, nil, fmt.Errorf("could not list ControllerConfigs: %w", err)
1588		}
1589	
1590		if len(controllerConfigs) == 0 {
1591			return nil, nil, fmt.Errorf("no ControllerConfigs found")
1592		}
1593	
1594		return secret.DeepCopy(), controllerConfigs[0].DeepCopy(), nil
1595	}
