1608	// deleteImage retrieves the necessary objects and calls DeleteImage on the imagepruner.
1609	func (b *buildReconciler) deleteImage(ctx context.Context, pullspec string, mosb *mcfgv1.MachineOSBuild) error {
1610		isOpenShiftRegistry, err := ctrlcommon.IsOpenShiftRegistry(ctx, pullspec, b.kubeclient, b.routeclient)
1611		if err != nil {
1612			return err
1613		}
1614	
1615		if isOpenShiftRegistry {
1616			klog.Infof("Deleting image %s from internal registry for MachineOSBuild %s", pullspec, mosb.Name)
1617			// Use the openshift API to delete the image
1618			ns, img, err := extractNSAndNameWithTag(pullspec)
1619			if err != nil {
1620				return err
1621			}
1622			if err := b.imageclient.ImageV1().ImageStreamTags(ns).Delete(context.TODO(), img, metav1.DeleteOptions{}); err != nil {
1623				if k8serrors.IsNotFound(err) {
1624					klog.Infof("image %s for MachineOSBuild %s not found", pullspec, mosb.Name)
1625					return nil
1626				}
1627				return fmt.Errorf("could not delete image %s from internal registry for MachineOSBuild %s: %w", pullspec, mosb.Name, err)
1628			}
1629			return nil
1630		}
1631	
1632		klog.Infof("Deleting image %s from external registry using skopeo for MachineOSBuild %s", pullspec, mosb.Name)
1633		secret, cc, err := b.getObjectsForImagePruner(mosb)
1634		if err != nil {
1635			return err
1636		}
1637	
1638		return b.imagepruner.DeleteImage(ctx, pullspec, secret, cc)
1639	}
