1641	// Determines if builds should be prevented due to pool degradation.
1642	// Returns true if pool has ANY degraded condition other than BuildDegraded,
1643	// but false if degraded ONLY due to BuildDegraded (to allow retry attempts).
1644	func (b *buildReconciler) shouldPreventBuildDueToDegradation(mcp *mcfgv1.MachineConfigPool) bool {
1645		// Check for ALL degradation conditions except BuildDegraded that should prevent new builds
1646		// We intentionally exclude BuildDegraded to allow retries
1647		// We check specific conditions rather than overall Degraded since Degraded=True could be due to BuildDegraded alone
1648		nonBuildDegradedTypes := []mcfgv1.MachineConfigPoolConditionType{
1649			mcfgv1.MachineConfigPoolNodeDegraded,
1650			mcfgv1.MachineConfigPoolRenderDegraded,
1651			mcfgv1.MachineConfigPoolPinnedImageSetsDegraded,
1652			mcfgv1.MachineConfigPoolSynchronizerDegraded,
1653		}
1654	
1655		for _, condType := range nonBuildDegradedTypes {
1656			if apihelpers.IsMachineConfigPoolConditionTrue(mcp.Status.Conditions, condType) {
1657				return true
1658			}
1659		}
1660	
1661		return false
1662	}
