1680	// Clears BuildDegraded condition when a new build starts (allowing retry after failure)
1681	func (b *buildReconciler) initializeBuildDegradedCondition(ctx context.Context, pool *mcfgv1.MachineConfigPool) error {
1682		// Check if BuildDegraded condition is already False - if so, no update needed
1683		if apihelpers.IsMachineConfigPoolConditionFalse(pool.Status.Conditions, mcfgv1.MachineConfigPoolImageBuildDegraded) {
1684			return nil
1685		}
1686	
1687		// Clear BuildDegraded condition (even if it was True from previous failure) when new build starts
1688		return retry.RetryOnConflict(retry.DefaultRetry, func() error {
1689			// Get fresh copy for update to avoid conflicts
1690			currentPool, err := b.mcfgclient.MachineconfigurationV1().MachineConfigPools().Get(ctx, pool.Name, metav1.GetOptions{})
1691			if err != nil {
1692				return err
1693			}
1694	
1695			buildDegraded := apihelpers.NewMachineConfigPoolCondition(mcfgv1.MachineConfigPoolImageBuildDegraded, corev1.ConditionFalse, string(mcfgv1.MachineConfigPoolBuilding), "Build started for pool "+currentPool.Name)
1696			apihelpers.SetMachineConfigPoolCondition(&currentPool.Status, *buildDegraded)
1697	
1698			_, err = b.mcfgclient.MachineconfigurationV1().MachineConfigPools().UpdateStatus(ctx, currentPool, metav1.UpdateOptions{})
1699			return err
1700		})
1701	}
