1703	// Clears BuildDegraded condition when build succeeds
1704	func (b *buildReconciler) syncBuildSuccessStatus(ctx context.Context, pool *mcfgv1.MachineConfigPool) error {
1705		return retry.RetryOnConflict(retry.DefaultRetry, func() error {
1706			// Get fresh copy for update to avoid conflicts
1707			currentPool, err := b.mcfgclient.MachineconfigurationV1().MachineConfigPools().Get(ctx, pool.Name, metav1.GetOptions{})
1708			if err != nil {
1709				return err
1710			}
1711	
1712			buildDegraded := apihelpers.NewMachineConfigPoolCondition(mcfgv1.MachineConfigPoolImageBuildDegraded, corev1.ConditionFalse, string(mcfgv1.MachineConfigPoolBuildSuccess), "Build succeeded for pool "+currentPool.Name)
1713			apihelpers.SetMachineConfigPoolCondition(&currentPool.Status, *buildDegraded)
1714	
1715			_, err = b.mcfgclient.MachineconfigurationV1().MachineConfigPools().UpdateStatus(ctx, currentPool, metav1.UpdateOptions{})
1716			return err
1717		})
1718	}
