1720	// Sets BuildDegraded condition when build fails
1721	func (b *buildReconciler) syncBuildFailureStatus(ctx context.Context, pool *mcfgv1.MachineConfigPool, buildErr error, mosbName string) error {
1722		updateErr := retry.RetryOnConflict(retry.DefaultRetry, func() error {
1723			// Get fresh copy for update to avoid conflicts
1724			currentPool, err := b.mcfgclient.MachineconfigurationV1().MachineConfigPools().Get(ctx, pool.Name, metav1.GetOptions{})
1725			if err != nil {
1726				return err
1727			}
1728	
1729			// The message content may be truncated https://github.com/kubernetes/apimachinery/blob/f5dd29d6ada12819a4a6ddc97d5bdf812f8a1cad/pkg/apis/meta/v1/types.go#L1619-L1635
1730			buildDegraded := apihelpers.NewMachineConfigPoolCondition(mcfgv1.MachineConfigPoolImageBuildDegraded, corev1.ConditionTrue, string(mcfgv1.MachineConfigPoolBuildFailed), fmt.Sprintf("Failed to build OS image for pool %s (MachineOSBuild: %s): %v", currentPool.Name, mosbName, buildErr))
1731			apihelpers.SetMachineConfigPoolCondition(&currentPool.Status, *buildDegraded)
1732	
1733			_, updateErr := b.mcfgclient.MachineconfigurationV1().MachineConfigPools().UpdateStatus(ctx, currentPool, metav1.UpdateOptions{})
1734			return updateErr
1735		})
1736		if updateErr != nil {
1737			klog.Errorf("Error updating MachineConfigPool %s BuildDegraded status: %v", pool.Name, updateErr)
1738		}
1739		return buildErr
1740	}
