1742	// getCurrentBuild finds the currently active (most relevant) build from a list of MachineOSBuilds
1743	// Priority: 1) Currently referenced by MOSC, 2) Building/Prepared, 3) Most recent
1744	func (b *buildReconciler) getCurrentBuild(mosc *mcfgv1.MachineOSConfig, mosbList []*mcfgv1.MachineOSBuild) *mcfgv1.MachineOSBuild {
1745		var activeBuild *mcfgv1.MachineOSBuild
1746		var mostRecentBuild *mcfgv1.MachineOSBuild
1747	
1748		// First, look for the build currently referenced by the MachineOSConfig
1749		for _, mosb := range mosbList {
1750			if isMachineOSBuildCurrentForMachineOSConfig(mosc, mosb) {
1751				activeBuild = mosb
1752				break
1753			}
1754		}
1755	
1756		// If no current build found, look for active builds (building/prepared)
1757		if activeBuild == nil {
1758			for _, mosb := range mosbList {
1759				mosbState := ctrlcommon.NewMachineOSBuildState(mosb)
1760				if mosbState.IsBuilding() || mosbState.IsBuildPrepared() {
1761					activeBuild = mosb
1762					break
1763				}
1764			}
1765		}
1766	
1767		// Keep track of the most recent build regardless
1768		for _, mosb := range mosbList {
1769			if mostRecentBuild == nil || mosb.CreationTimestamp.After(mostRecentBuild.CreationTimestamp.Time) {
1770				mostRecentBuild = mosb
1771			}
1772		}
1773	
1774		// If still no active build, use the most recent one
1775		if activeBuild == nil {
1776			activeBuild = mostRecentBuild
1777		}
1778	
1779		return activeBuild
1780	}
