1782	// updateImageBuildDegradedCondition examines all MachineOSBuilds for the MachineOSConfig
1783	// and sets the ImageBuildDegraded condition based on the status of the currently active build
1784	func (b *buildReconciler) updateImageBuildDegradedCondition(ctx context.Context, pool *mcfgv1.MachineConfigPool, mosc *mcfgv1.MachineOSConfig) error {
1785		mosbList, err := b.getMachineOSBuildsForMachineOSConfig(mosc)
1786		if err != nil {
1787			return fmt.Errorf("could not get MachineOSBuilds for MachineOSConfig %q: %w", mosc.Name, err)
1788		}
1789	
1790		// Find the currently active build
1791		activeBuild := b.getCurrentBuild(mosc, mosbList)
1792	
1793		// If no builds exist at all, clear any existing BuildDegraded condition
1794		if activeBuild == nil {
1795			return b.syncBuildSuccessStatus(ctx, pool)
1796		}
1797	
1798		// Update condition based on the active build's status
1799		activeState := ctrlcommon.NewMachineOSBuildState(activeBuild)
1800	
1801		switch {
1802		case activeState.IsBuildFailure():
1803			// Set BuildDegraded=True for failed builds
1804			buildError := getBuildErrorFromMOSB(activeBuild)
1805			return b.syncBuildFailureStatus(ctx, pool, buildError, activeBuild.Name)
1806		case activeState.IsBuildSuccess():
1807			// Clear BuildDegraded=False for successful builds
1808			return b.syncBuildSuccessStatus(ctx, pool)
1809		case activeState.IsBuilding(), activeState.IsBuildPrepared():
1810			// Clear BuildDegraded=False for builds in progress (allow retry after previous failure)
1811			return b.initializeBuildDegradedCondition(ctx, pool)
1812		}
1813	
1814		// For any other states, don't change the condition
1815		return nil
1816	}
