1818	// seedMachineOSConfigWithExistingImage handles the seeding of a MachineOSConfig with a pre-built image
1819	func (b *buildReconciler) seedMachineOSConfigWithExistingImage(ctx context.Context, mosc *mcfgv1.MachineOSConfig, imageSpec string) error {
1820		// Step 1: Ensure required push secret exists from bootstrap
1821		if mosc.Spec.RenderedImagePushSecret.Name == "" {
1822			return fmt.Errorf("MachineOSConfig %q has no rendered image push secret", mosc.Name)
1823		}
1824		if err := b.ensureBootstrapSecretExists(ctx, mosc.Spec.RenderedImagePushSecret.Name); err != nil {
1825			return fmt.Errorf("could not ensure push secret %s exists: %w", mosc.Spec.RenderedImagePushSecret.Name, err)
1826		}
1827	
1828		// Step 2: Generate expected MachineOSBuild using existing MCO logic
1829		mcp, err := b.machineConfigPoolLister.Get(mosc.Spec.MachineConfigPool.Name)
1830		if err != nil {
1831			return fmt.Errorf("could not get MachineConfigPool %q: %w", mosc.Spec.MachineConfigPool.Name, err)
1832		}
1833	
1834		mc, err := b.machineConfigLister.Get(mcp.Spec.Configuration.Name)
1835		if err != nil {
1836			return fmt.Errorf("could not get MachineConfig: %q: %w", mcp.Spec.Configuration.Name, err)
1837		}
1838	
1839		templateMOSB, err := buildrequest.NewMachineOSBuild(buildrequest.MachineOSBuildOpts{
1840			MachineConfig:     mc,
1841			MachineConfigPool: mcp,
1842			MachineOSConfig:   mosc,
1843		})
1844	
1845		if err != nil {
1846			return fmt.Errorf("could not generate MachineOSBuild template for MachineOSConfig %q: %w", mosc.Name, err)
1847		}
1848	
1849		// Step 2: Create synthetic MachineOSBuild with success status
1850		syntheticMOSB, err := b.createSyntheticMachineOSBuild(ctx, mosc, templateMOSB.Name, imageSpec)
1851		if err != nil {
1852			return fmt.Errorf("could not create synthetic MachineOSBuild for MachineOSConfig %q: %w", mosc.Name, err)
1853		}
1854	
1855		// Step 3: Update MachineOSConfig with build annotation and status
1856		if err := b.updateMachineOSConfigForSeeding(ctx, mosc, syntheticMOSB, imageSpec); err != nil {
1857			return fmt.Errorf("could not update MachineOSConfig %q for seeding: %w", mosc.Name, err)
1858		}
1859	
1860		klog.Infof("Successfully seeded MachineOSConfig %q with pre-built image %q", mosc.Name, imageSpec)
1861		return nil
1862	}
