1864	// createSyntheticMachineOSBuild creates a MachineOSBuild object for pre-built images
1865	func (b *buildReconciler) createSyntheticMachineOSBuild(ctx context.Context, mosc *mcfgv1.MachineOSConfig, buildName, imageSpec string) (*mcfgv1.MachineOSBuild, error) {
1866		// Get current rendered MachineConfig for the pool
1867		mcp, err := b.machineConfigPoolLister.Get(mosc.Spec.MachineConfigPool.Name)
1868		if err != nil {
1869			return nil, fmt.Errorf("could not get MachineConfigPool %q: %w", mosc.Spec.MachineConfigPool.Name, err)
1870		}
1871	
1872		// Generate build metadata using the same utility as normal OCL workflow
1873		buildLabels := utils.GetMachineOSBuildLabels(mosc, mcp)
1874		// Add pre-built image marker
1875		buildLabels[constants.PreBuiltImageLabelKey] = constants.TrueValue
1876	
1877		buildAnnotations := map[string]string{
1878			constants.RenderedImagePushSecretAnnotationKey: mosc.Spec.RenderedImagePushSecret.Name,
1879		}
1880	
1881		now := metav1.Now()
1882		// buildEnd must be after buildStart for API validation
1883		buildEnd := metav1.NewTime(now.Add(1 * time.Second))
1884	
1885		// Set owner reference to the MachineOSConfig (matching normal OCL workflow)
1886		oref := metav1.NewControllerRef(mosc, mcfgv1.SchemeGroupVersion.WithKind("MachineOSConfig"))
1887	
1888		// Create MachineOSBuild object matching the normal OCL workflow template
1889		mosb := &mcfgv1.MachineOSBuild{
1890			TypeMeta: metav1.TypeMeta{
1891				Kind:       "MachineOSBuild",
1892				APIVersion: "machineconfiguration.openshift.io/v1",
1893			},
1894			ObjectMeta: metav1.ObjectMeta{
1895				Name:   buildName,
1896				Labels: buildLabels,
1897				Finalizers: []string{
1898					metav1.FinalizerDeleteDependents,
1899				},
1900				Annotations:     buildAnnotations,
1901				OwnerReferences: []metav1.OwnerReference{*oref},
1902			},
1903			Spec: mcfgv1.MachineOSBuildSpec{
1904				RenderedImagePushSpec: mosc.Spec.RenderedImagePushSpec,
1905				MachineConfig: mcfgv1.MachineConfigReference{
1906					Name: mcp.Spec.Configuration.Name,
1907				},
1908				MachineOSConfig: mcfgv1.MachineOSConfigReference{
1909					Name: mosc.Name,
1910				},
1911			},
1912			Status: mcfgv1.MachineOSBuildStatus{
1913				BuildStart:            &now,
1914				BuildEnd:              &buildEnd,
1915				DigestedImagePushSpec: mcfgv1.ImageDigestFormat(imageSpec),
1916				Conditions: []metav1.Condition{
1917					{
1918						Type:               string(mcfgv1.MachineOSBuildSucceeded),
1919						Status:             metav1.ConditionTrue,
1920						LastTransitionTime: now,
1921						Reason:             constants.ReasonPreBuiltImageSeeded,
1922						Message:            fmt.Sprintf("Pre-built image %q successfully seeded", imageSpec),
1923					},
1924					{
1925						Type:               string(mcfgv1.MachineOSBuildPrepared),
1926						Status:             metav1.ConditionFalse,
1927						LastTransitionTime: now,
1928						Reason:             constants.ReasonPreBuiltImageSeeded,
1929						Message:            "Skipped: using pre-built image",
1930					},
1931					{
1932						Type:               string(mcfgv1.MachineOSBuilding),
1933						Status:             metav1.ConditionFalse,
1934						LastTransitionTime: now,
1935						Reason:             constants.ReasonPreBuiltImageSeeded,
1936						Message:            "Skipped: using pre-built image",
1937					},
1938					{
1939						Type:               string(mcfgv1.MachineOSBuildFailed),
1940						Status:             metav1.ConditionFalse,
1941						LastTransitionTime: now,
1942						Reason:             constants.ReasonPreBuiltImageSeeded,
1943						Message:            "Skipped: using pre-built image",
1944					},
1945					{
1946						Type:               string(mcfgv1.MachineOSBuildInterrupted),
1947						Status:             metav1.ConditionFalse,
1948						LastTransitionTime: now,
1949						Reason:             constants.ReasonPreBuiltImageSeeded,
1950						Message:            "Skipped: using pre-built image",
1951					},
1952				},
1953			},
1954		}
1955	
1956		// Check if the MachineOSBuild already exists (may have been created by normal workflow due to timing)
1957		existingMOSB, err := b.mcfgclient.MachineconfigurationV1().MachineOSBuilds().Get(ctx, buildName, metav1.GetOptions{})
1958		if err != nil && !k8serrors.IsNotFound(err) {
1959			return nil, fmt.Errorf("could not check if MachineOSBuild %q exists: %w", buildName, err)
1960		}
1961	
1962		var createdMOSB *mcfgv1.MachineOSBuild
1963		if k8serrors.IsNotFound(err) {
1964			// Create the MachineOSBuild object (status will be ignored on creation)
1965			createdMOSB, err = b.mcfgclient.MachineconfigurationV1().MachineOSBuilds().Create(ctx, mosb, metav1.CreateOptions{})
1966			if err != nil {
1967				return nil, fmt.Errorf("could not create synthetic MachineOSBuild %q: %w", buildName, err)
1968			}
1969			klog.Infof("Created synthetic MachineOSBuild %q for pre-built image %q", buildName, imageSpec)
1970		} else {
1971			// MachineOSBuild already exists - this can happen due to race between seeding and normal workflow
1972			klog.Infof("MachineOSBuild %q already exists, converting to synthetic build with success status", buildName)
1973	
1974			// Update the existing MOSB to have the pre-built-image label if it doesn't already
1975			if existingMOSB.Labels == nil {
1976				existingMOSB.Labels = make(map[string]string)
1977			}
1978			if existingMOSB.Labels[constants.PreBuiltImageLabelKey] != constants.TrueValue {
1979				existingMOSB.Labels[constants.PreBuiltImageLabelKey] = constants.TrueValue
1980				existingMOSB, err = b.mcfgclient.MachineconfigurationV1().MachineOSBuilds().Update(ctx, existingMOSB, metav1.UpdateOptions{})
1981				if err != nil {
1982					return nil, fmt.Errorf("could not update labels on existing MachineOSBuild %q: %w", buildName, err)
1983				}
1984			}
1985			createdMOSB = existingMOSB
1986		}
1987	
1988		// Update the status separately (status is ignored on Create and must always be set for synthetic builds)
1989		createdMOSB.Status = mosb.Status
1990		updatedMOSB, err := b.mcfgclient.MachineconfigurationV1().MachineOSBuilds().UpdateStatus(ctx, createdMOSB, metav1.UpdateOptions{})
1991		if err != nil {
1992			return nil, fmt.Errorf("could not update status on synthetic MachineOSBuild %q: %w", buildName, err)
1993		}
1994	
1995		klog.Infof("Updated status on synthetic MachineOSBuild %q with success condition", buildName)
1996		return updatedMOSB, nil
1997	}
