1999	// updateMachineOSConfigForSeeding updates MachineOSConfig for seeded state
2000	func (b *buildReconciler) updateMachineOSConfigForSeeding(ctx context.Context, mosc *mcfgv1.MachineOSConfig, mosb *mcfgv1.MachineOSBuild, imageSpec string) error {
2001		// Update annotations - set current build annotation to mark seeding as complete
2002		// The currentBuild annotation serves as the marker that seeding has occurred
2003		metav1.SetMetaDataAnnotation(&mosc.ObjectMeta, constants.CurrentMachineOSBuildAnnotationKey, mosb.Name)
2004	
2005		// Update the MachineOSConfig object
2006		updatedMOSC, err := b.mcfgclient.MachineconfigurationV1().MachineOSConfigs().Update(ctx, mosc, metav1.UpdateOptions{})
2007		if err != nil {
2008			return fmt.Errorf("could not update MachineOSConfig %q annotations: %w", mosc.Name, err)
2009		}
2010	
2011		// Update status with current image
2012		updatedMOSC.Status.CurrentImagePullSpec = mcfgv1.ImageDigestFormat(imageSpec)
2013		updatedMOSC.Status.ObservedGeneration = updatedMOSC.GetGeneration()
2014		updatedMOSC.Status.MachineOSBuild = &mcfgv1.ObjectReference{
2015			Name:     mosb.Name,
2016			Group:    mcfgv1.SchemeGroupVersion.Group,
2017			Resource: "machineosbuilds",
2018		}
2019	
2020		// Add conditions indicating seeded state
2021		seededCondition := metav1.Condition{
2022			Type:               constants.MachineOSConfigSeeded,
2023			Status:             metav1.ConditionTrue,
2024			LastTransitionTime: metav1.NewTime(time.Now()),
2025			Reason:             constants.ReasonPreBuiltImageSeeded,
2026			Message:            fmt.Sprintf("MachineOSConfig seeded with pre-built image %q", imageSpec),
2027		}
2028	
2029		// Add the condition to the status
2030		updatedMOSC.Status.Conditions = append(updatedMOSC.Status.Conditions, seededCondition)
2031	
2032		_, err = b.mcfgclient.MachineconfigurationV1().MachineOSConfigs().UpdateStatus(ctx, updatedMOSC, metav1.UpdateOptions{})
2033		if err != nil {
2034			return fmt.Errorf("could not update MachineOSConfig %q status: %w", mosc.Name, err)
2035		}
2036	
2037		klog.Infof("Updated MachineOSConfig %q status with pre-built image %q", mosc.Name, imageSpec)
2038		return nil
2039	}
