2041	// ensureBootstrapSecretExists verifies that the required secret exists in the MCO namespace.
2042	// Secrets are expected to be created from bootstrap manifests when the cluster starts up.
2043	func (b *buildReconciler) ensureBootstrapSecretExists(ctx context.Context, secretName string) error {
2044		// Check if the secret exists in the MCO namespace
2045		_, err := b.kubeclient.CoreV1().Secrets(ctrlcommon.MCONamespace).Get(ctx, secretName, metav1.GetOptions{})
2046		if err == nil {
2047			// Secret exists
2048			klog.V(4).Infof("Secret %s exists in MCO namespace", secretName)
2049			return nil
2050		}
2051	
2052		if k8serrors.IsNotFound(err) {
2053			return fmt.Errorf("required secret %s not found in %s namespace. Ensure the secret was created from bootstrap manifests or exists in the cluster", secretName, ctrlcommon.MCONamespace)
2054		}
2055	
2056		return fmt.Errorf("failed to check if secret %s exists: %w", secretName, err)
2057	}

