103	// Creates all of the ConfigMap objects needed for the build such as the
104	// Containerfile, MachineConfig and AdditionalTrustBundle ConfigMaps.
105	func (br buildRequestImpl) ConfigMaps() ([]*corev1.ConfigMap, error) {
106		containerfile, err := br.containerfileToConfigMap()
107		if err != nil {
108			return nil, err
109		}
110	
111		machineconfig, err := br.machineconfigToConfigMap(br.opts.MachineConfig)
112		if err != nil {
113			if br.opts.MachineConfig != nil {
114				return nil, fmt.Errorf("could not convert MachineConfig %q into ConfigMap %q: %w", br.opts.MachineConfig.Name, br.getMCConfigMapName(), err)
115			}
116	
117			return nil, fmt.Errorf("could not convert MachineConfig into ConfigMap %q: %w", br.getMCConfigMapName(), err)
118		}
119	
120		additionaltrustbundle := br.additionaltrustbundleToConfigMap()
121	
122		etcPolicy, err := br.etcPolicyToConfigMap(br.opts.MachineConfig)
123		if err != nil {
124			return nil, fmt.Errorf("could not convert etc/containers registries files into ConfigMap %q: %w", br.getEtcPolicyConfigMapName(), err)
125		}
126		etcRegistries, err := br.etcRegistriesToConfigMap(br.opts.MachineConfig)
127		if err != nil {
128			return nil, fmt.Errorf("could not convert registries.conf files into ConfigMap %q: %w", br.getEtcRegistriesConfigMapName(), err)
129		}
130	
131		configMaps := []*corev1.ConfigMap{containerfile, machineconfig, additionaltrustbundle}
132		if etcPolicy != nil {
133			configMaps = append(configMaps, etcPolicy)
134		} else {
135			klog.Warningf("/etc/containers/policy.json file not found in MachineConfig %q, could not create ConfigMap %q", br.opts.MachineConfig.Name, br.getEtcPolicyConfigMapName())
136		}
137		if etcRegistries != nil {
138			configMaps = append(configMaps, etcRegistries)
139		} else {
140			klog.Warningf("/etc/containers/registries.conf file not found in MachineConfig %q, could not create ConfigMap %q", br.opts.MachineConfig.Name, br.getEtcRegistriesConfigMapName())
141		}
142	
143		return configMaps, nil
144	}
