146	func (br buildRequestImpl) canonicalizeSecret(name string, secret *corev1.Secret) (*corev1.Secret, error) {
147		canonicalized, err := canonicalizePullSecret(secret)
148		if err != nil {
149			return nil, fmt.Errorf("could not canonicalize pull secret %q: %w", name, err)
150		}
151	
152		// Overwrite the ObjectMeta so that we get all of the labels and annotations.
153		objMeta := br.getObjectMeta(name)
154		for k, v := range canonicalized.Labels {
155			objMeta.Labels[k] = v
156		}
157	
158		canonicalized.ObjectMeta = objMeta
159		return canonicalized, nil
160	}
