262	func (br buildRequestImpl) ignitionFileToConfigMapData(mc *mcfgv1.MachineConfig, filePath, prefixToTrim string) (map[string]string, error) {
263		if len(mc.Spec.Config.Raw) == 0 {
264			return nil, nil
265		}
266		// Build the ConfigMap data
267		ignCfg, err := ctrlcommon.ParseAndConvertConfig(mc.Spec.Config.Raw)
268		if err != nil {
269			return nil, fmt.Errorf("parsing rendered MC Ignition config failed with error: %w", err)
270		}
271	
272		for _, file := range ignCfg.Storage.Files {
273			if file.Path != filePath {
274				continue
275			}
276			if file.Contents.Source == nil {
277				return nil, fmt.Errorf("nil source for %s", file.Path)
278			}
279	
280			// Extract and decode the encoded data
281			decodedData, err := chelpers.DecodeIgnitionFileContents(file.Contents.Source, file.Contents.Compression)
282			if err != nil {
283				return nil, fmt.Errorf("error decoding %s: %w", file.Path, err)
284			}
285	
286			// Key in the configmap is the path without the prefix
287			fileKey := strings.TrimPrefix(file.Path, prefixToTrim)
288			return map[string]string{fileKey: string(decodedData)}, nil
289		}
290		klog.Infof("Could not find %s in MachineConfig %s, skipping configmap creation....", filePath, mc.Name)
291		return nil, nil
292	}
