294	// Renders our Containerfile template.
295	//
296	// TODO: Figure out how to parse the Containerfile using
297	// https://github.com/openshift/imagebuilder/tree/master/containerfile/parser to
298	// ensure that we've generated a valid Containerfile.
299	//
300	// TODO: Figure out how to programatically generate the Containerfile using a
301	// higher-level abstraction than just naïvely rendering a text template and
302	// hoping for the best.
303	func (br buildRequestImpl) renderContainerfile() (string, error) {
304		tmpl, err := template.New("containerfile").Parse(containerfileTemplate)
305		if err != nil {
306			return "", fmt.Errorf("could not parse containerfile template: %w", err)
307		}
308	
309		extPkgs, err := br.opts.getExtensionsPackages()
310		if err != nil {
311			return "", err
312		}
313	
314		kernelType, kernelPackages, err := br.opts.getKernelPackages()
315		if err != nil {
316			return "", err
317		}
318	
319		out := &strings.Builder{}
320	
321		// This anonymous struct is necessary because templates cannot access
322		// lowercase fields. Additionally, since there are a few fields where we
323		// default to a value from a different location, it makes more sense for us
324		// to implement that logic in Go as opposed to the Go template language.
325		items := struct {
326			MachineOSBuild     *mcfgv1.MachineOSBuild
327			MachineOSConfig    *mcfgv1.MachineOSConfig
328			UserContainerfile  string
329			BaseOSImage        string
330			ExtensionsImage    string
331			ExtensionsPackages []string
332			KernelType         string
333			KernelPackages     map[string][]string
334		}{
335			MachineOSBuild:     br.opts.MachineOSBuild,
336			MachineOSConfig:    br.opts.MachineOSConfig,
337			UserContainerfile:  br.userContainerfile,
338			BaseOSImage:        br.opts.MachineConfig.Spec.OSImageURL,
339			ExtensionsImage:    br.opts.MachineConfig.Spec.BaseOSExtensionsContainerImage,
340			ExtensionsPackages: extPkgs,
341			KernelType:         kernelType,
342			KernelPackages:     kernelPackages,
343		}
344	
345		if err := tmpl.Execute(out, items); err != nil {
346			return "", fmt.Errorf("could not execute containerfile template: %w", err)
347		}
348	
349		return out.String(), nil
350	}
