352	// podToJob creates a Job with the spec of the given Pod
353	func (br buildRequestImpl) podToJob(pod *corev1.Pod) *batchv1.Job {
354		// Set the backoffLimit to 3 so the job will retry 4 times before reporting a failure
355		var backoffLimit int32 = constants.JobMaxRetries
356	
357		// Set completion to 1 so that as soon as the pod has completed successfully the job is
358		// considered a success
359		var completions int32 = constants.JobCompletions
360	
361		// Set the owner ref of the job to the MOSB
362		oref := metav1.NewControllerRef(br.opts.MachineOSBuild, mcfgv1.SchemeGroupVersion.WithKind("MachineOSBuild"))
363	
364		return &batchv1.Job{
365			ObjectMeta: metav1.ObjectMeta{
366				Name:            pod.ObjectMeta.Name,
367				Namespace:       pod.ObjectMeta.Namespace,
368				Labels:          pod.ObjectMeta.Labels,
369				Annotations:     pod.ObjectMeta.Annotations,
