387	// We're able to run the Buildah image in an unprivileged pod provided that the
388	// machine-os-builder service account has the anyuid security constraint
389	// context enabled to allow us to use UID 1000, which maps to the UID within
390	// the official Buildah image.
391	// nolint:dupl // I don't want to deduplicate this yet since there are still some unknowns.
392	func (br buildRequestImpl) toBuildahPod() *corev1.Pod {
393		var httpProxy, httpsProxy, noProxy string
394		if br.opts.Proxy != nil {
395			httpProxy = br.opts.Proxy.HTTPProxy
396			httpsProxy = br.opts.Proxy.HTTPSProxy
397			noProxy = br.opts.Proxy.NoProxy
398		}
399		env := []corev1.EnvVar{
400			// How many times the build / push steps should be retried. In the future,
401			// this should be wired up to the MachineOSConfig or other higher-level
402			// APbr. This is useful for retrying builds / pushes when they fail due to a
403			// transient condition such as a temporary network issue. It does *NOT*
404			// handle situations where the build pod is evicted or rescheduled. A
405			// higher-level abstraction will be needed such as a Kubernetes Job
406			// (https://kubernetes.io/docs/concepts/workloads/controllers/job/).
407			{
408				Name:  "MAX_RETRIES",
409				Value: "3",
410			},
411			{
412				Name:  "DIGEST_CONFIGMAP_NAME",
413				Value: br.getDigestConfigMapName(),
414			},
415			{
416				Name: "DIGEST_CONFIGMAP_LABELS",
417				// Gets the labels for all objects created by imageBuildRequest, converts
418				// them into a string representation, and replaces the separating commas
419				// with spaces.
420				Value: strings.ReplaceAll(labels.Set(br.getLabelsForObjectMeta()).String(), ",", " "),
421			},
422			{
423				Name:  "HOME",
424				Value: "/home/build",
425			},
426			{
427				Name:  "TAG",
428				Value: string(br.opts.MachineOSBuild.Spec.RenderedImagePushSpec),
429			},
430			{
431				Name:  "BASE_IMAGE_PULL_CREDS",
432				Value: "/tmp/base-image-pull-creds/config.json",
433			},
434			{
435				Name:  "FINAL_IMAGE_PUSH_CREDS",
436				Value: "/tmp/final-image-push-creds/config.json",
437			},
438			{
439				Name:  "BUILDAH_ISOLATION",
440				Value: "chroot",
441			},
442			{
443				Name:  "HTTP_PROXY",
444				Value: httpProxy,
445			},
446			{
447				Name:  "HTTPS_PROXY",
448				Value: httpsProxy,
449			},
450			{
451				Name:  "NO_PROXY",
452				Value: noProxy,
453			},
454			{
455				Name:  "BASE_OS_IMAGE_PULLSPEC",
456				Value: br.opts.MachineConfig.Spec.OSImageURL,
457			},
458		}
459	
460		securityContext := &corev1.SecurityContext{}
461	
462		command := []string{"/bin/bash", "-c"}
463	
464		volumeMounts := []corev1.VolumeMount{
465			{
466				Name:      "machineconfig",
467				MountPath: "/tmp/machineconfig",
468			},
469			{
470				Name:      "containerfile",
471				MountPath: "/tmp/containerfile",
472			},
473			{
474				Name:      "etc-policy",
475				MountPath: "/etc/containers/policy.json",
476				SubPath:   "policy.json",
477			},
478			{
479				Name:      "etc-registries",
480				MountPath: "/etc/containers/registries.conf",
481				SubPath:   "registries.conf",
482			},
483			{
484				Name:      "additional-trust-bundle",
485				MountPath: "/etc/pki/ca-trust/source/anchors",
486			},
487			{
488				Name:      "base-image-pull-creds",
489				MountPath: "/tmp/base-image-pull-creds",
490			},
491			{
492				Name:      "final-image-push-creds",
493				MountPath: "/tmp/final-image-push-creds",
494			},
495			{
496				Name:      "done",
497				MountPath: "/tmp/done",
498			},
499		}
500	
501		boolTrue := true
502		volumes := []corev1.Volume{
503			{
504				// Provides the rendered Containerfile.
505				Name: "containerfile",
506				VolumeSource: corev1.VolumeSource{
507					ConfigMap: &corev1.ConfigMapVolumeSource{
508						LocalObjectReference: corev1.LocalObjectReference{
509							Name: br.getContainerfileConfigMapName(),
510						},
511					},
512				},
513			},
514			{
515				// Provides the rendered MachineConfig in a gzipped / base64-encoded
516				// format.
517				Name: "machineconfig",
518				VolumeSource: corev1.VolumeSource{
519					ConfigMap: &corev1.ConfigMapVolumeSource{
520						LocalObjectReference: corev1.LocalObjectReference{
521							Name: br.getMCConfigMapName(),
522						},
523					},
524				},
525			},
526			{
527				// Provides the user defined Additional Trust Bundle
528				Name: "additional-trust-bundle",
529				VolumeSource: corev1.VolumeSource{
530					ConfigMap: &corev1.ConfigMapVolumeSource{
531						LocalObjectReference: corev1.LocalObjectReference{
532							Name: br.getAdditionalTrustBundleConfigMapName(),
533						},
534					},
535				},
536			},
537			{
538				// Provides the /etc/containers/policy.json content from the node
539				Name: "etc-policy",
540				VolumeSource: corev1.VolumeSource{
541					ConfigMap: &corev1.ConfigMapVolumeSource{
542						LocalObjectReference: corev1.LocalObjectReference{
543							Name: br.getEtcPolicyConfigMapName(),
544						},
545						Optional: &boolTrue,
546					},
547				},
548			},
549			{
550				// Provides the /etc/containers/registries.conf content from the node
551				Name: "etc-registries",
552				VolumeSource: corev1.VolumeSource{
553					ConfigMap: &corev1.ConfigMapVolumeSource{
554						LocalObjectReference: corev1.LocalObjectReference{
555							Name: br.getEtcRegistriesConfigMapName(),
556						},
557						Optional: &boolTrue,
558					},
559				},
560			},
561			{
562				// Provides the credentials needed to pull the base OS image.
563				Name: "base-image-pull-creds",
564				VolumeSource: corev1.VolumeSource{
565					Secret: &corev1.SecretVolumeSource{
566						SecretName: br.getBasePullSecretName(),
567						// SecretName: br.opts.MachineOSConfig.Spec.BuildInputs.BaseImagePullSecret.Name,
568						Items: []corev1.KeyToPath{
569							{
570								Key:  corev1.DockerConfigJsonKey,
571								Path: "config.json",
572							},
573						},
574					},
575				},
576			},
577			{
578				// Provides the credentials needed to push the final OS image.
579				Name: "final-image-push-creds",
580				VolumeSource: corev1.VolumeSource{
581					Secret: &corev1.SecretVolumeSource{
582						// SecretName: br.opts.MachineOSConfig.Spec.BuildInputs.RenderedImagePushSecret.Name,
583						SecretName: br.getFinalPushSecretName(),
584						Items: []corev1.KeyToPath{
585							{
586								Key:  corev1.DockerConfigJsonKey,
587								Path: "config.json",
588							},
589						},
590					},
591				},
592			},
593			{
594				// Provides a way for the "image-build" container to signal that it
595				// finished so that the "wait-for-done" container can retrieve the
596				// iamge SHA.
597				Name: "done",
598				VolumeSource: corev1.VolumeSource{
599					EmptyDir: &corev1.EmptyDirVolumeSource{
600						Medium: corev1.StorageMediumMemory,
601					},
602				},
603			},
604			{
605				// This provides a dedicated place for Buildah to store / cache its
606				// images during the build. This seems to be required for the build-time
607				// volume mounts to work correctly, most likely due to an issue with
608				// SELinux that I have yet to figure out. Despite being called a cache
609				// directory, it gets removed whenever the build pod exits
610				Name: "buildah-cache",
611				VolumeSource: corev1.VolumeSource{
612					EmptyDir: &corev1.EmptyDirVolumeSource{},
613				},
614			},
615		}
616	
617		// If the etc-pki-entitlement secret is found, mount it into the build pod.
618		if br.opts.HasEtcPkiEntitlementKeys {
619			opts := optsForEtcPkiEntitlements()
620			env = append(env, opts.envVar())
621			volumeMounts = append(volumeMounts, opts.volumeMount())
622			volumes = append(volumes, opts.volumeForSecret(constants.EtcPkiEntitlementSecretName+"-"+br.opts.MachineOSConfig.Spec.MachineConfigPool.Name))
623		}
624	
625		// If the etc-yum-repos-d ConfigMap is found, mount it into the build pod.
626		if br.opts.HasEtcYumReposDConfigs {
627			opts := optsForEtcYumReposD()
628			env = append(env, opts.envVar())
629			volumeMounts = append(volumeMounts, opts.volumeMount())
630			volumes = append(volumes, opts.volumeForConfigMap())
631		}
632	
633		// If the etc-pki-rpm-gpg secret is found, mount it into the build pod.
634		if br.opts.HasEtcPkiRpmGpgKeys {
635			opts := optsForEtcRpmGpgKeys()
636			env = append(env, opts.envVar())
637			volumeMounts = append(volumeMounts, opts.volumeMount())
638			volumes = append(volumes, opts.volumeForSecret(constants.EtcPkiRpmGpgSecretName))
639		}
640	
641		var terminationGracePeriodSeconds int64 = 10
642	
643		return &corev1.Pod{
644			TypeMeta: metav1.TypeMeta{
645				APIVersion: "v1",
646				Kind:       "Pod",
647			},
648			ObjectMeta: br.getObjectMeta(br.getBuildName()),
649			Spec: corev1.PodSpec{
650				RestartPolicy: corev1.RestartPolicyNever,
651				// Run the build process in an init container so that we can report accurate
652				// status if the build process is successful but the configmap creation container fails
653				InitContainers: []corev1.Container{
654					{
655						// This container performs the image build / push process.
656						Name:                     "image-build",
657						Image:                    br.opts.Images.MachineConfigOperator,
658						Env:                      env,
659						Command:                  append(command, buildahBuildScript),
660						ImagePullPolicy:          corev1.PullAlways,
661						SecurityContext:          securityContext,
662						TerminationMessagePolicy: corev1.TerminationMessageFallbackToLogsOnError,
663						// Only attach the buildah-cache volume mount to the buildah container.
664						VolumeMounts: append(volumeMounts, corev1.VolumeMount{
665							Name:      "buildah-cache",
666							MountPath: "/home/build/.local/share/containers",
667						}),
668					},
669				},
670				Containers: []corev1.Container{
671					{
672						// This container waits for the init container doing the build to finish
673						// building so we can get the final image SHA. We do this by using
674						// the base OS image (which contains the "oc" binary) to create a
675						// ConfigMap from the digestfile that Buildah creates, which allows
676						// us to avoid parsing log files.
677						Name:                     "create-digest-configmap",
678						Command:                  append(command, digestCMScript),
679						Image:                    br.opts.MachineConfig.Spec.OSImageURL,
680						Env:                      env,
681						ImagePullPolicy:          corev1.PullAlways,
682						SecurityContext:          securityContext,
683						TerminationMessagePolicy: corev1.TerminationMessageFallbackToLogsOnError,
684						VolumeMounts:             volumeMounts,
685					},
686				},
687				ServiceAccountName:            "machine-os-builder",
688				Volumes:                       volumes,
689				TerminationGracePeriodSeconds: &terminationGracePeriodSeconds,
690			},
691		}
692	}
