78	// Runs the preparer and creates the build job.
79	func (j *jobImageBuilder) Start(ctx context.Context) error {
80		if _, err := j.start(ctx); err != nil {
81			return j.addMachineOSBuildNameToError(fmt.Errorf("could not start job: %w", err))
