87	func (j *jobImageBuilder) start(ctx context.Context) (*batchv1.Job, error) {
88		builder, err := j.prepareForBuild(ctx)
89		if err != nil {
90			return nil, err
91		}
92	
93		if err := j.validateBuilderType(builder); err != nil {
94			return nil, err
95		}
96	
97		mosbName, err := j.getMachineOSBuildName()
98		if err != nil {
99			return nil, err
100		}
101	
102		buildJob := builder.GetObject().(*batchv1.Job)
103	
104		bj, err := j.kubeclient.BatchV1().Jobs(ctrlcommon.MCONamespace).Create(ctx, buildJob, metav1.CreateOptions{})
105		if err == nil {
106			klog.Infof("Build job %q created for MachineOSBuild %q", bj.Name, mosbName)
107	
108			// Set the job UID as an annotation in the MOSB
109			if j.mosb != nil {
110				metav1.SetMetaDataAnnotation(&j.mosb.ObjectMeta, constants.JobUIDAnnotationKey, string(bj.UID))
111				// Update the MOSB with the new annotations
112				_, err := j.mcfgclient.MachineconfigurationV1().MachineOSBuilds().Update(ctx, j.mosb, metav1.UpdateOptions{})
113				if err != nil && !k8serrors.IsNotFound(err) {
114					return nil, fmt.Errorf("could not update MachineOSBuild %s with job UID annotation: %w", mosbName, err)
115				}
116			}
117	
118			// Set the owner reference of the configmaps and secrets created to be the Job
119			// Set blockOwnerDeletion and Controller to false as Job ownership doesn't work when set to true
120			oref := metav1.NewControllerRef(bj, batchv1.SchemeGroupVersion.WithKind("Job"))
121			falseBool := false
122			oref.BlockOwnerDeletion = &falseBool
123			oref.Controller = &falseBool
124	
125			cms, err := j.buildrequest.ConfigMaps()
126			if err != nil {
127				return nil, err
128			}
129			for _, cm := range cms {
130				cm.SetOwnerReferences([]metav1.OwnerReference{*oref})
131				if _, err := j.kubeclient.CoreV1().ConfigMaps(ctrlcommon.MCONamespace).Update(ctx, cm, metav1.UpdateOptions{}); err != nil {
132					return nil, err
133				}
134			}
135	
136			secrets, err := j.buildrequest.Secrets()
137			if err != nil {
138				return nil, err
139			}
140			for _, secret := range secrets {
141				secret.SetOwnerReferences([]metav1.OwnerReference{*oref})
142				if _, err := j.kubeclient.CoreV1().Secrets(ctrlcommon.MCONamespace).Update(ctx, secret, metav1.UpdateOptions{}); err != nil {
143					return nil, err
144				}
145			}
146			return bj, nil
147		}
148	
149		if k8serrors.IsAlreadyExists(err) {
150			return j.getBuildJobStrict(ctx)
151		}
152	
153		return nil, fmt.Errorf("could not create build job: %w", err)
154	}
