158		if j.getBuilderName() == "" {
159			return nil, fmt.Errorf("imagebuilder missing name for MachineOSBuild or builder")
160		}
161	
162		return j.kubeclient.BatchV1().Jobs(ctrlcommon.MCONamespace).Get(ctx, j.getBuilderName(), metav1.GetOptions{})
163	}
