179	// Determines whether the given build job exists in the API server.
180	func (j *jobImageBuilder) Exists(ctx context.Context) (bool, error) {
181		job, err := j.getBuildJobStrict(ctx)
182		if err == nil && job != nil {
183			return true, nil
184		}
185	
186		if k8serrors.IsNotFound(err) {
187			return false, nil
188		}
189	
190		return false, j.addMachineOSBuildNameToError(fmt.Errorf("could not determine if build pod exists: %w", err))
191	}
