195		status, err := j.machineOSBuildStatus(ctx)
196		if err != nil {
197			return status, j.addMachineOSBuildNameToError(fmt.Errorf("could not get MachineOSBuildStatus: %w", err))
198		}
199	
200		return status, nil
201	}
