203	// Gets the build job from either the provided builder (if present) or the API server.
204	func (j *jobImageBuilder) getBuildJobFromBuilderOrAPI(ctx context.Context) (*batchv1.Job, error) {
205		if j.builder != nil {
206			if err := j.validateBuilderType(j.builder); err != nil {
207				return nil, fmt.Errorf("could not get build job from builder: %w", err)
208			}
209	
210			job := j.builder.GetObject().(*batchv1.Job)
211	
212			// Ensure that the job UID matches the jobUID annotation in the MOSB so that
213			// we know that we are using the correct job to set the status of the MOSB
214			if jobIsForMOSB(job, j.mosb) {
215				klog.V(4).Infof("Using provided build job %s", string(job.UID))
216				return job, nil
217			}
218		}
219	
220		job, err := j.getBuildJobStrict(ctx)
221		if err != nil {
222			return nil, fmt.Errorf("could not get build job from API: %w", err)
223		}
224	
225		klog.V(4).Infof("Using build job from API %s", string(job.UID))
226		return job, nil
227	}
