229	func (j *jobImageBuilder) getStatus(ctx context.Context) (*batchv1.Job, mcfgv1.BuildProgress, []metav1.Condition, error) {
230		job, err := j.getBuildJobFromBuilderOrAPI(ctx)
231		if err != nil {
232			return nil, "", nil, err
233		}
234	
235		status, conditions := MapJobStatusToBuildStatus(job)
236	
237		klog.Infof("Build job %q status %+v mapped to MachineOSBuild progress %q", job.Name, job.Status, status)
238	
239		return job, status, conditions, nil
240	}
