242	func (j *jobImageBuilder) machineOSBuildStatus(ctx context.Context) (mcfgv1.MachineOSBuildStatus, error) {
243		job, status, conditions, err := j.getStatus(ctx)
244		if err != nil {
245			return mcfgv1.MachineOSBuildStatus{}, err
246		}
247	
248		buildStatus, err := j.getMachineOSBuildStatus(ctx, job, status, conditions)
249		if err != nil {
250			return mcfgv1.MachineOSBuildStatus{}, err
251		}
252	
253		return buildStatus, nil
254	}
