266	// Stops the running build by deleting the build job.
267	func (j *jobImageBuilder) Stop(ctx context.Context) error {
268		if err := j.stop(ctx); err != nil {
269			return j.addMachineOSBuildNameToError(fmt.Errorf("could not stop build job: %w", err))
270		}
271	
272		return nil
273	}
274	
275	func (j *jobImageBuilder) stop(ctx context.Context) error {
276		mosbName, err := j.getMachineOSBuildName()
277		if err != nil {
278			return fmt.Errorf("could not get MachineOSBuild name to stop build job: %w", err)
279		}
280	
281		buildJob, err := j.getBuildJobFromBuilderOrAPI(ctx)
282		if k8serrors.IsNotFound(err) {
283			return nil
284		}
285		if err != nil {
286			return fmt.Errorf("could not get Job to stop build job: %w", err)
287		}
288	
289		// Ensure that the job being deleted is for the MOSB we are currently reconciling
290		if !jobIsForMOSB(buildJob, j.mosb) {
291			klog.Infof("Build job %q with UID %s is not owned by MachineOSBuild %q, will not delete", buildJob.Name, buildJob.UID, mosbName)
292			return nil
293		}
294		propagationPolicy := metav1.DeletePropagationForeground
295		err = j.kubeclient.BatchV1().Jobs(ctrlcommon.MCONamespace).Delete(ctx, buildJob.Name, metav1.DeleteOptions{PropagationPolicy: &propagationPolicy})
296		if err == nil {
297			klog.Infof("Deleted build job %s for MachineOSBuild %s", buildJob.Name, mosbName)
298			return nil
299		}
300	
301		if k8serrors.IsNotFound(err) {
302			return nil
303		}
304	
305		return fmt.Errorf("could not delete build job %s for MachineOSBuild %s", buildJob.Name, mosbName)
306	}
307	
308	// Stops the running build by calling Stop() and also removes all of the
309	// ephemeral objects that were created for the build.
310	func (j *jobImageBuilder) Clean(ctx context.Context) error {
311		err := errors.Join(j.Stop(ctx), j.cleaner.Clean(ctx))
312		if err != nil {
313			return j.addMachineOSBuildNameToError(fmt.Errorf("could not clean up build job objects: %w", err))
314		}
315	
316		return nil
317	}
