319	// Validates that a builders' concrete type is a job.
320	func (j *jobImageBuilder) validateBuilderType(builder buildrequest.Builder) error {
321		_, ok := builder.GetObject().(*batchv1.Job)
322		if ok {
323			return nil
324		}
325	
326		return fmt.Errorf("invalid type %T from builder, expected %T", j.builder, &batchv1.Job{})
327	}
