329	// Maps a given batchv1.Job to a given MachineOSBuild status. Exported so that it can be used in e2e tests.
330	func MapJobStatusToBuildStatus(job *batchv1.Job) (mcfgv1.BuildProgress, []metav1.Condition) {
331		// If the job is being deleted and it was not in either a successful or failed state
332		// then the MachineOSBuild should be considered "interrupted"
333		if job.DeletionTimestamp != nil && job.Status.Succeeded == 0 && job.Status.Failed < constants.JobMaxRetries+1 {
334			return mcfgv1.MachineOSBuildInterrupted, apihelpers.MachineOSBuildInterruptedConditions()
335		}
336	
337		if job.Status.Active == 0 && job.Status.Succeeded == 0 && job.Status.Failed == 0 && job.Status.UncountedTerminatedPods == nil {
338			return mcfgv1.MachineOSBuildPrepared, apihelpers.MachineOSBuildPendingConditions()
339		}
340		// The build job is still running till it succeeds or maxes out it retries on failures
341		if job.Status.Active >= 0 && job.Status.Failed >= 0 && job.Status.Failed < constants.JobMaxRetries+1 && job.Status.Succeeded == 0 {
342			return mcfgv1.MachineOSBuilding, apihelpers.MachineOSBuildRunningConditions()
343		}
344	
345		// For jobs with init containers, we need to verify that the job actually completed successfully
346		// Job.Status.Succeeded > 0 only indicates that at least one pod succeeded, but with init containers,
347		// a pod can be marked as succeeded even if regular containers fail after init containers succeed.
348		// We need to check the job's actual completion condition.
349		if job.Status.Succeeded > 0 {
350			if len(job.Status.Conditions) == 0 {
351				return mcfgv1.MachineOSBuildSucceeded, apihelpers.MachineOSBuildSucceededConditions()
352			}
353			// Check if the job has the "Complete" condition set to true
354			for _, condition := range job.Status.Conditions {
355				if condition.Type == batchv1.JobComplete && condition.Status == corev1.ConditionTrue {
356					return mcfgv1.MachineOSBuildSucceeded, apihelpers.MachineOSBuildSucceededConditions()
357				}
358				if condition.Type == batchv1.JobFailed && condition.Status == corev1.ConditionTrue {
359					return mcfgv1.MachineOSBuildFailed, apihelpers.MachineOSBuildFailedConditions()
360				}
361			}
362			// If we have succeeded pods but no completion condition, we're still building
363			return mcfgv1.MachineOSBuilding, apihelpers.MachineOSBuildRunningConditions()
364		}
365	
366		// Only return failed if there have been 4 pod failures as the backoffLimit is set to 3
367		if job.Status.Failed > constants.JobMaxRetries {
368			return mcfgv1.MachineOSBuildFailed, apihelpers.MachineOSBuildFailedConditions()
369		}
370	
371		return "", apihelpers.MachineOSBuildInitialConditions()
372	}
373	
374	// Returns true if the provided job UID matches the job UID annotation in the provided MachineOSBuild
375	func jobIsForMOSB(job *batchv1.Job, mosb *mcfgv1.MachineOSBuild) bool {
376		if mosb == nil {
377			return false
378		}
379	
380		if string(job.UID) != mosb.GetAnnotations()[constants.JobUIDAnnotationKey] {
381			return false
382		}
383	
384		return true
385	}
