20	// This is the same salt / pattern from pkg/controller/render/hash.go
21	var (
22		// salt is 80 random bytes.
23		// The salt was generated by `od -vAn -N80 -tu1 < /dev/urandom`. Do not change it.
24		salt = []byte{
25			16, 124, 206, 228, 139, 56, 175, 175, 79, 229, 134, 118, 157, 154, 211, 110,
26			25, 93, 47, 253, 172, 106, 37, 7, 174, 13, 160, 185, 110, 17, 87, 52,
27			219, 131, 12, 206, 218, 141, 116, 135, 188, 181, 192, 151, 233, 62, 126, 165,
28			64, 83, 179, 119, 15, 168, 208, 197, 146, 107, 58, 227, 133, 188, 238, 26,
29			33, 26, 235, 202, 32, 173, 31, 234, 41, 144, 148, 79, 6, 206, 23, 22,
30		}
31	)
32	
33	// Holds the objects that are used to construct a MachineOSBuild with a hashed
34	// name.
35	type MachineOSBuildOpts struct {
36		MachineConfig     *mcfgv1.MachineConfig
37		MachineOSConfig   *mcfgv1.MachineOSConfig
38		MachineConfigPool *mcfgv1.MachineConfigPool
39	}
40	
41	// Validates that the required options are provided.
42	func (m *MachineOSBuildOpts) validateForHash() error {
43		if err := m.validateMachineConfig(); err != nil {
44			return fmt.Errorf("machineconfig failed validation: %w", err)
45		}
46	
47		if m.MachineOSConfig == nil {
48			return fmt.Errorf("missing required MachineOSConfig")
49		}
50	
51		if m.MachineConfigPool == nil {
52			return fmt.Errorf("missing required MachineConfigPool")
53		}
54	
55		if m.MachineConfigPool.Name != m.MachineOSConfig.Spec.MachineConfigPool.Name {
56			return fmt.Errorf("name mismatch, MachineConfigPool has %q, MachineOSConfig has %q", m.MachineConfigPool.Name, m.MachineOSConfig.Spec.MachineConfigPool.Name)
57		}
58	
59		return nil
60	}
61	
62	// Validates that a MachineConfig has the necessary metadata for generating a
63	// MachineOSBuild.
64	func (m *MachineOSBuildOpts) validateMachineConfig() error {
65		if m.MachineConfig == nil {
66			return fmt.Errorf("missing required MachineConfig")
67		}
68	
69		if !strings.HasPrefix(m.MachineConfig.Name, ctrlcommon.RenderedMachineConfigPrefix) {
70			return fmt.Errorf("machineconfig %q is not a rendered MachineConfig", m.MachineConfig.Name)
71		}
72	
73		requiredAnnos := []string{ctrlcommon.ReleaseImageVersionAnnotationKey, ctrlcommon.GeneratedByControllerVersionAnnotationKey}
74		for _, anno := range requiredAnnos {
75			val, ok := m.MachineConfig.Annotations[anno]
76			if !ok {
77				return fmt.Errorf("missing annotation %q on MachineConfig %q", anno, m.MachineConfig.Name)
78			}
79	
80			if val == "" {
81				return fmt.Errorf("empty annotation %q value on MachineConfig %q", anno, m.MachineConfig.Name)
82			}
83		}
84	
85		return nil
86	}
87	
88	// Creates a list of objects that are consumed by the SHA256 hash.
89	func (m *MachineOSBuildOpts) objectsForHash() []interface{} {
90		// Represents a private version of the OSImageURLConfig struct to keep the
91		// hashed name generation stable regardless of the input source. This means
92		// that we can eventually remove the OSImageURLConfig struct.
93		type osImageURLConfig struct {
94			BaseOSContainerImage           string
95			BaseOSExtensionsContainerImage string
96			OSImageURL                     string
97			ReleaseVersion                 string
98		}
99	
100		cfg := osImageURLConfig{
101			BaseOSContainerImage:           m.MachineConfig.Spec.OSImageURL,
102			BaseOSExtensionsContainerImage: m.MachineConfig.Spec.BaseOSExtensionsContainerImage,
103			// To maintain stable hashing, this field is purposely left empty because
104			// these values were originally populated from the
105			// "machine-config-osimageurl" ConfigMap. The ConfigMap field which
106			// populates this struct field is blank.
107			OSImageURL:     "",
108			ReleaseVersion: m.MachineConfig.Annotations[ctrlcommon.ReleaseImageVersionAnnotationKey],
109		}
110	
111		// The objects considered for hashing described inline:
112		out := []interface{}{
113			// The configuration of the MachineConfigPool object. This includes the
114			// name of the rendered MachineConfig as well as the reference of all of
115			// the individual MachineConfigs that went into that rendered
116			// MachineConfig.
117			m.MachineConfigPool.Spec.Configuration,
118			// The MachineOSConfig Spec field.
119			m.MachineOSConfig.Spec,
120			// The complete osImageURLConfig object.
121			cfg,
122		}
123	
124		return out
125	}
126	
127	// Gets the hashed name including the MachineOSConfig name. This is in the
128	// format of "<mosc name>-<md5 hash>"
129	func (m *MachineOSBuildOpts) getHashedNameWithConfig() (string, error) {
130		hash, err := m.getHashedName()
131		if err != nil {
132			return "", fmt.Errorf("could not get hashed name: %w", err)
133		}
134	
135		return fmt.Sprintf("%s-%s", m.MachineOSConfig.Name, hash), nil
136	}
137	
138	// Returns solely the hash of all of the provided objects.
139	func (m *MachineOSBuildOpts) getHashedName() (string, error) {
140		if err := m.validateForHash(); err != nil {
141			return "", fmt.Errorf("could not validate for hash: %w", err)
142		}
143	
144		//nolint:gosec
145		hasher := md5.New()
146		if _, err := hasher.Write(salt); err != nil {
147			return "", fmt.Errorf("error writing salt: %w", err)
148		}
149	
150		for _, obj := range m.objectsForHash() {
151			// Produce the hash by getting a YAML representation of each object that is
152			// considered and writing the YAML bytes to the Write interface for the
153			// hashing library.
154			data, err := yaml.Marshal(obj)
155	
156			if err != nil {
157				return "", fmt.Errorf("could not marshal object to YAML: %w", err)
158			}
159	
160			if _, err := hasher.Write(data); err != nil {
161				return "", fmt.Errorf("error writing object to hash: %w", err)
162			}
163		}
164	
165		return fmt.Sprintf("%x", hasher.Sum(nil)), nil
166	}
167	
168	// Constructs a new MachineOSBuild object or panics trying. Useful for testing
169	// scenarios.
170	func NewMachineOSBuildOrDie(opts MachineOSBuildOpts) *mcfgv1.MachineOSBuild {
171		mosb, err := NewMachineOSBuild(opts)
172	
173		if err != nil {
174			panic(err)
175		}
176	
177		return mosb
178	}
179	
180	// Constructs a new MachineOSBuild object with all of the labels, the tagged
181	// image pushpsec, and a hashed name.
182	func NewMachineOSBuild(opts MachineOSBuildOpts) (*mcfgv1.MachineOSBuild, error) {
183		mosbName, err := opts.getHashedNameWithConfig()
184		if err != nil {
185			return nil, fmt.Errorf("could not get hashed name for MachineOSBuild: %w", err)
186		}
187	
188		now := metav1.Now()
189	
190		namedRef, err := reference.ParseNamed(string(opts.MachineOSConfig.Spec.RenderedImagePushSpec))
191		if err != nil {
192			return nil, err
193		}
194	
195		taggedRef, err := reference.WithTag(namedRef, mosbName)
196		if err != nil {
197			return nil, err
198		}
199	
200		mosb := &mcfgv1.MachineOSBuild{
201			TypeMeta: metav1.TypeMeta{
202				Kind:       "MachineOSBuild",
203				APIVersion: "machineconfiguration.openshift.io/v1",
204			},
205			ObjectMeta: metav1.ObjectMeta{
206				Name:   mosbName,
207				Labels: utils.GetMachineOSBuildLabels(opts.MachineOSConfig, opts.MachineConfigPool),
208				// Set finalzer on MOSB to ensure all it dependents are deleted before the MOSB
209				Finalizers: []string{
210					metav1.FinalizerDeleteDependents,
211				},
212				Annotations: map[string]string{
213					constants.RenderedImagePushSecretAnnotationKey: opts.MachineOSConfig.Spec.RenderedImagePushSecret.Name,
214				},
215			},
216			Spec: mcfgv1.MachineOSBuildSpec{
217				RenderedImagePushSpec: mcfgv1.ImageTagFormat(taggedRef.String()),
218				MachineConfig: mcfgv1.MachineConfigReference{
219					Name: opts.MachineConfigPool.Spec.Configuration.Name,
220				},
221				MachineOSConfig: mcfgv1.MachineOSConfigReference{
222					Name: opts.MachineOSConfig.Name,
223				},
224			},
225			Status: mcfgv1.MachineOSBuildStatus{
226				BuildStart: &now,
227			},
228		}
229	
230		return mosb, nil
231	}
