143		}
144	
145		return ""
146	}
147	
148	func (b *MachineOSBuildState) IsAnyDegraded() bool {
149		condTypes := []mcfgv1.BuildProgress{
150			mcfgv1.MachineOSBuildFailed,
151			mcfgv1.MachineOSBuildInterrupted,
152		}
153	
154		for _, condType := range condTypes {
155			if apihelpers.IsMachineOSBuildConditionTrue(b.Build.Status.Conditions, condType) {
156				return true
157			}
158		}
159	
160		return false
161	}
162	
163	// Idempotently sets the supplied build conditions.
164	func (b *MachineOSBuildState) SetBuildConditions(conditions []metav1.Condition) {
165		for _, condition := range conditions {
166			condition := condition
167			currentCondition := apihelpers.GetMachineOSBuildCondition(b.Build.Status, mcfgv1.BuildProgress(condition.Type))
168			if currentCondition != nil && isConditionEqual(*currentCondition, condition) {
169				continue
170			}
171	
172			mosbCondition := apihelpers.NewMachineOSBuildCondition(condition.Type, condition.Status, condition.Reason, condition.Message)
173			apihelpers.SetMachineOSBuildCondition(&b.Build.Status, *mosbCondition)
174		}
175	}
176	
177	// Returns a map of the buildprogress states to their expected conditions for
178	// transient states. That is, the MachineOSBuild is expected to transition from
179	// one state to another.
180	func MachineOSBuildTransientStates() map[mcfgv1.BuildProgress][]metav1.Condition {
181		return map[mcfgv1.BuildProgress][]metav1.Condition{
182			mcfgv1.MachineOSBuilding:      apihelpers.MachineOSBuildRunningConditions(),
183			mcfgv1.MachineOSBuildPrepared: apihelpers.MachineOSBuildPendingConditions(),
184		}
185	}
186	
187	// Returns a map of the buildprogress states to their expected conditions for
188	// terminal states; meaning that the MachineOSBuild cannot transition from one
189	// state to another.
190	func MachineOSBuildTerminalStates() map[mcfgv1.BuildProgress][]metav1.Condition {
191		return map[mcfgv1.BuildProgress][]metav1.Condition{
192			mcfgv1.MachineOSBuildSucceeded:   apihelpers.MachineOSBuildSucceededConditions(),
193			mcfgv1.MachineOSBuildFailed:      apihelpers.MachineOSBuildFailedConditions(),
194			mcfgv1.MachineOSBuildInterrupted: apihelpers.MachineOSBuildInterruptedConditions(),
195		}
196	}
197	
198	// Determines if two conditions are equal. Note: I purposely do not include the
199	// timestamp in the equality test, since we do not directly set it.
200	func isConditionEqual(cond1, cond2 metav1.Condition) bool {
201		return cond1.Type == cond2.Type &&
202			cond1.Status == cond2.Status &&
203			cond1.Message == cond2.Message &&
204			cond1.Reason == cond2.Reason
205	}
206	
207	func clearAllBuildConditions(inConditions []metav1.Condition) []metav1.Condition {
208		conditions := []metav1.Condition{}
209	
210		for _, condition := range inConditions {
211			buildConditionFound := false
212			for _, buildConditionType := range getMachineConfigBuildConditions() {
213				if condition.Type == string(buildConditionType) {
214					buildConditionFound = true
215					break
216				}
217			}
218	
219			if !buildConditionFound {
220				conditions = append(conditions, condition)
221			}
222		}
223	
224		return conditions
225	}
226	
227	func getMachineConfigBuildConditions() []mcfgv1.BuildProgress {
228		return []mcfgv1.BuildProgress{
229			mcfgv1.MachineOSBuildFailed,
230			mcfgv1.MachineOSBuildInterrupted,
231			mcfgv1.MachineOSBuildPrepared,
232			mcfgv1.MachineOSBuildSucceeded,
233			mcfgv1.MachineOSBuilding,
234		}
235	}
236	
237	func IsPoolAnyDegraded(pool *mcfgv1.MachineConfigPool) bool {
238		condTypes := []mcfgv1.MachineConfigPoolConditionType{
239			mcfgv1.MachineConfigPoolDegraded,
240			mcfgv1.MachineConfigPoolNodeDegraded,
241			mcfgv1.MachineConfigPoolRenderDegraded,
242		}
243	
244		for _, condType := range condTypes {
245			if apihelpers.IsMachineConfigPoolConditionTrue(pool.Status.Conditions, condType) {
246				return true
247			}
248		}
249	
250		return false
251	}
252	
253	// Determine if we have a config change.
254	func IsPoolConfigChange(oldPool, curPool *mcfgv1.MachineConfigPool) bool {
255		return oldPool.Spec.Configuration.Name != curPool.Spec.Configuration.Name
256	}
257	
258	func HasBuildObjectForCurrentMachineConfig(pool *mcfgv1.MachineConfigPool, mosb *mcfgv1.MachineOSBuild) bool {
259		return pool.Spec.Configuration.Name == mosb.Spec.MachineConfig.Name
260	}
261	
262	// Determines if we should do a build based upon the state of our
263	// MachineConfigPool, the presence of a build pod, etc.
264	func BuildDueToPoolChange(oldPool, curPool *mcfgv1.MachineConfigPool, moscNew *mcfgv1.MachineOSConfig, mosbNew *mcfgv1.MachineOSBuild) bool {
265	
266		moscState := NewMachineOSConfigState(moscNew)
267		mosbState := NewMachineOSBuildState(mosbNew)
268	
269		// If we don't have a layered pool, we should not build.
270		poolStateSuggestsBuild := canPoolBuild(curPool, moscState, mosbState) &&
271			// If we have a config change or we're missing an image pullspec label, we
272			// should do a build.
273			(IsPoolConfigChange(oldPool, curPool) || !moscState.HasOSImage())
274	
275		return poolStateSuggestsBuild
276	
277	}
278	
279	// Checks our pool to see if we can do a build. We base this off of a few criteria:
280	// 1. Is the pool opted into layering?
281	// 2. Do we have an object reference to an in-progress build?
282	// 3. Is the pool degraded?
283	// 4. Is our build in a specific state?
284	//
285	// Returns true if we are able to build.
286	func canPoolBuild(pool *mcfgv1.MachineConfigPool, moscNewState *MachineOSConfigState, mosbNewState *MachineOSBuildState) bool {
287		// If we don't have a layered pool, we should not build.
288		if !IsLayeredPool(moscNewState.Config, mosbNewState.Build) {
289			return false
290		}
291		// If the pool is degraded, we should not build.
292		if IsPoolAnyDegraded(pool) {
293			return false
294		}
295		// If the new pool has an ongoing build, we should not build
296		if mosbNewState.Build != nil {
297			return false
298		}
299		return true
300	}
301	
302	func IsLayeredPool(mosc *mcfgv1.MachineOSConfig, mosb *mcfgv1.MachineOSBuild) bool {
303		return (mosc != nil || mosb != nil)
304	}
305

1	package apihelpers
2	
3	import (
4		mcfgv1 "github.com/openshift/api/machineconfiguration/v1"
5	
6		metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
7	)
8	
9	// NewMachineOSConfigCondition creates a new MachineOSConfig condition.
10	func NewMachineOSConfigCondition(condType string, status metav1.ConditionStatus, reason, message string) *metav1.Condition {
11		return &metav1.Condition{
12			Type:               condType,
13			Status:             status,
14			LastTransitionTime: metav1.Now(),
15			Reason:             reason,
16			Message:            message,
17		}
18	}
19	
20	func GetMachineOSConfigCondition(status mcfgv1.MachineOSConfigStatus, condType string) *metav1.Condition {
21		// in case of sync errors, return the last condition that matches, not the first
22		// this exists for redundancy and potential race conditions.
23		var LatestState *metav1.Condition
24		for i := range status.Conditions {
25			c := status.Conditions[i]
26			if c.Type == condType {
27				LatestState = &c
28			}
29		}
30		return LatestState
31	}
32	
33	// SetMachineOSConfigCondition updates the MachineOSConfig to include the provided condition. If the condition that
34	// we are about to add already exists and has the same status and reason then we are not going to update.
35	func SetMachineOSConfigCondition(status *mcfgv1.MachineOSConfigStatus, condition metav1.Condition) {
36		currentCond := GetMachineOSConfigCondition(*status, condition.Type)
37		if currentCond != nil && currentCond.Status == condition.Status && currentCond.Reason == condition.Reason && currentCond.Message == condition.Message {
38			return
39		}
40		// Do not update lastTransitionTime if the status of the condition doesn't change.
41		if currentCond != nil && currentCond.Status == condition.Status {
42			condition.LastTransitionTime = currentCond.LastTransitionTime
43		}
44	
45		// this may not be necessary
46		newConditions := filterOutMachineOSConfigCondition(status.Conditions, condition.Type)
47		newConditions = append(newConditions, condition)
48		status.Conditions = newConditions
49	}
50	
51	// RemoveMachineOSConfigCondition removes the MachineOSConfig condition with the provided type.
52	func RemoveMachineOSConfigCondition(status *mcfgv1.MachineOSConfigStatus, condType string) {
53		status.Conditions = filterOutMachineOSConfigCondition(status.Conditions, condType)
54	}
55	
56	// filterOutMachineOSConfigCondition returns a new slice of MachineOSConfig conditions without conditions with the provided type.
57	func filterOutMachineOSConfigCondition(conditions []metav1.Condition, condType string) []metav1.Condition {
58		var newConditions []metav1.Condition
59		for _, c := range conditions {
60			if c.Type == condType {
61				continue
62			}
63			newConditions = append(newConditions, c)
64		}
65		return newConditions
66	}
67	
68	func IsMachineOSConfigConditionTrue(conditions []metav1.Condition, conditionType string) bool {
69		return IsMachineOSConfigConditionPresentAndEqual(conditions, conditionType, metav1.ConditionTrue)
70	}
71	
72	// IsMachineOSConfigConditionPresentAndEqual returns true when conditionType is present and equal to status.
73	func IsMachineOSConfigConditionPresentAndEqual(conditions []metav1.Condition, conditionType string, status metav1.ConditionStatus) bool {
74		for _, condition := range conditions {
75			if condition.Type == conditionType {
76				return condition.Status == status
77			}
78		}
79		return false
80	}
