17	
18	// The Preparer object creates all of the ephemeral build objects required for
19	// a build to take place. This includes the ConfigMaps which contains the
20	// rendered MachineConfig and the Containerfile, as well as cloned copies of
21	// any secrets required for the build to take place. Similarly, the Preparer
22	// object knows how to destroy all of the objects that it creates. It does so
23	// by using a specific label query.
24	type preparerImpl struct {
25		mosb       *mcfgv1.MachineOSBuild
26		mosc       *mcfgv1.MachineOSConfig
27		kubeclient clientset.Interface
28		mcfgclient mcfgclientset.Interface
29	}
30	
31	func NewPreparer(kubeclient clientset.Interface, mcfgclient mcfgclientset.Interface, mosb *mcfgv1.MachineOSBuild, mosc *mcfgv1.MachineOSConfig) Preparer {
32		return &preparerImpl{
33			kubeclient: kubeclient,
34			mcfgclient: mcfgclient,
35			mosb:       mosb.DeepCopy(),
36			mosc:       mosc.DeepCopy(),
37		}
38	}
39	
40	func (p *preparerImpl) Prepare(ctx context.Context) (buildrequest.BuildRequest, error) {
41		br, err := buildrequest.NewBuildRequestFromAPI(ctx, p.kubeclient, p.mcfgclient, p.mosb, p.mosc)
42		if err != nil {
43			return nil, fmt.Errorf("could not get imagebuildrequestopts: %w", err)
44		}
45	
46		if err := p.createEphemeralBuildObjects(ctx, br); err != nil {
47			return nil, fmt.Errorf("could not create ephemeral build objects: %w", err)
48		}
49	
50		return br, nil
51	}
52	
53	func (p *preparerImpl) createEphemeralBuildObjects(ctx context.Context, br buildrequest.BuildRequest) error {
54		configmaps, err := br.ConfigMaps()
55		if err != nil {
56			return err
57		}
58	
59		secrets, err := br.Secrets()
60		if err != nil {
61			return err
62		}
63	
64		for _, configmap := range configmaps {
65			if err := p.createConfigMap(ctx, configmap); err != nil {
66				return fmt.Errorf("could not create ephemeral configmap %s for build %s: %w", configmap.Name, p.mosb.Name, err)
67			}
68		}
69	
70		for _, secret := range secrets {
71			if err := p.createSecret(ctx, secret); err != nil {
72				return fmt.Errorf("could not create ephemeral secret %s for build %s: %w", secret.Name, p.mosb.Name, err)
73			}
74		}
75	
76		klog.Infof("All ephemeral objects for MachineOSBuild %s created", p.mosb.Name)
77	
78		return nil
79	}
